import React, { useEffect, useRef } from 'react';
import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls';

const tags = [
  '⚙️ Mechanical', '⚡ Electrical', '📡 IoT',
  '📟 Embedded', '🤖 Robotics', '💻 Software',
  '🔩 Hardware', '🧊 3D Design',
];

function buildGear(teeth, innerR, outerR, toothW = 0.45, depth = 0.18) {
  const shape = new THREE.Shape();
  const total = teeth * 2;
  for (let i = 0; i < total; i++) {
    const a0 = (i / total) * Math.PI * 2;
    const a1 = ((i + toothW) / total) * Math.PI * 2;
    const a2 = ((i + toothW + 0.05) / total) * Math.PI * 2;
    const a3 = ((i + 1) / total) * Math.PI * 2;
    const r0 = i % 2 === 0 ? outerR : innerR;
    const r1 = i % 2 === 0 ? outerR : innerR;
    const r2 = i % 2 === 0 ? innerR : outerR;
    const r3 = i % 2 === 0 ? innerR : outerR;
    const fn = i === 0 ? 'moveTo' : 'lineTo';
    shape[fn](Math.cos(a0) * r0, Math.sin(a0) * r0);
    shape.lineTo(Math.cos(a1) * r1, Math.sin(a1) * r1);
    shape.lineTo(Math.cos(a2) * r2, Math.sin(a2) * r2);
    shape.lineTo(Math.cos(a3) * r3, Math.sin(a3) * r3);
  }
  shape.closePath();
  const hole = new THREE.Path();
  hole.absarc(0, 0, innerR * 0.42, 0, Math.PI * 2, true);
  shape.holes.push(hole);
  const geo = new THREE.ExtrudeGeometry(shape, {
    depth, bevelEnabled: true,
    bevelThickness: 0.018, bevelSize: 0.012, bevelSegments: 2,
  });
  geo.center();
  return geo;
}

function buildHub(r, depth) {
  return new THREE.CylinderGeometry(r, r, depth + 0.05, 32);
}

export default function Home({ onNavigate }) {
  const mountRef = useRef(null);

  useEffect(() => {
    const mount = mountRef.current;
    if (!mount) return;

    const W = mount.clientWidth;
    const H = mount.clientHeight;

    const renderer = new THREE.WebGLRenderer({ antialias: true, alpha: true });
    renderer.setSize(W, H);
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setClearColor(0x000000, 0);
    mount.appendChild(renderer.domElement);

    const scene  = new THREE.Scene();
    const camera = new THREE.PerspectiveCamera(50, W / H, 0.1, 100);
    camera.position.set(0, 0.4, 5.2);

    const controls = new OrbitControls(camera, renderer.domElement);
    controls.enableDamping   = true;
    controls.dampingFactor   = 0.06;
    controls.enableZoom      = true;
    controls.zoomSpeed       = 0.6;
    controls.minDistance     = 3;
    controls.maxDistance     = 9;
    controls.autoRotate      = true;
    controls.autoRotateSpeed = 0.6;
    controls.addEventListener('start', () => { controls.autoRotate = false; });

    scene.add(new THREE.AmbientLight(0xffffff, 0.25));
    const dirLight = new THREE.DirectionalLight(0x00f5ff, 1.8);
    dirLight.position.set(4, 6, 5);
    scene.add(dirLight);
    const backLight = new THREE.DirectionalLight(0xbf00ff, 1.2);
    backLight.position.set(-4, -3, -3);
    scene.add(backLight);
    const rimLight = new THREE.DirectionalLight(0x00f5ff, 0.5);
    rimLight.position.set(0, -5, 2);
    scene.add(rimLight);

    const matCyan = new THREE.MeshStandardMaterial({
      color: 0x003344, emissive: 0x00b8cc, emissiveIntensity: 0.35,
      metalness: 0.9, roughness: 0.25,
    });
    const matPurple = new THREE.MeshStandardMaterial({
      color: 0x1a0033, emissive: 0x8800cc, emissiveIntensity: 0.4,
      metalness: 0.9, roughness: 0.2,
    });
    const matAccent = new THREE.MeshStandardMaterial({
      color: 0x002233, emissive: 0x004466, emissiveIntensity: 0.5,
      metalness: 0.95, roughness: 0.15,
    });

    const gearGroup = new THREE.Group();
    scene.add(gearGroup);

    // Big gear
    const bigGear = new THREE.Mesh(buildGear(16, 0.72, 1.05, 0.42, 0.22), matCyan);
    bigGear.position.set(-0.9, 0.15, 0);
    gearGroup.add(bigGear);
    const bigHub = new THREE.Mesh(buildHub(0.28, 0.22), matAccent);
    bigHub.rotation.x = Math.PI / 2;
    bigHub.position.copy(bigGear.position);
    gearGroup.add(bigHub);

    // Medium gear
    const medOuter = 0.68;
    const medGear = new THREE.Mesh(buildGear(10, 0.46, medOuter, 0.42, 0.20), matPurple);
    medGear.position.set(-0.9 + 1.05 + medOuter - 0.05, 0.15, 0);
    gearGroup.add(medGear);
    const medHub = new THREE.Mesh(buildHub(0.18, 0.20), matAccent);
    medHub.rotation.x = Math.PI / 2;
    medHub.position.copy(medGear.position);
    gearGroup.add(medHub);

    // Small gear
    const smOuter = 0.44;
    const smGear = new THREE.Mesh(buildGear(6, 0.30, smOuter, 0.42, 0.18), matCyan);
    smGear.position.set(medGear.position.x, medGear.position.y + medOuter + smOuter - 0.04, 0.04);
    gearGroup.add(smGear);
    const smHub = new THREE.Mesh(buildHub(0.12, 0.18), matAccent);
    smHub.rotation.x = Math.PI / 2;
    smHub.position.copy(smGear.position);
    gearGroup.add(smHub);

    // Tiny gear
    const tinyOuter = 0.52;
    const tinyGear = new THREE.Mesh(buildGear(8, 0.35, tinyOuter, 0.42, 0.16), matPurple);
    tinyGear.position.set(bigGear.position.x - 0.1, bigGear.position.y - 1.05 - tinyOuter + 0.04, -0.05);
    gearGroup.add(tinyGear);
    const tinyHub = new THREE.Mesh(buildHub(0.14, 0.16), matAccent);
    tinyHub.rotation.x = Math.PI / 2;
    tinyHub.position.copy(tinyGear.position);
    gearGroup.add(tinyHub);

    // Particles
    const pCount = 90;
    const pPos = new Float32Array(pCount * 3);
    for (let i = 0; i < pCount; i++) {
      pPos[i*3]   = (Math.random()-0.5)*5;
      pPos[i*3+1] = (Math.random()-0.5)*5;
      pPos[i*3+2] = (Math.random()-0.5)*3;
    }
    const pGeo = new THREE.BufferGeometry();
    pGeo.setAttribute('position', new THREE.BufferAttribute(pPos, 3));
    const particles = new THREE.Points(pGeo, new THREE.PointsMaterial({
      color: 0x00f5ff, size: 0.025, transparent: true, opacity: 0.5,
    }));
    scene.add(particles);

    const bigSpeed  =  0.28;
    const medSpeed  = -(16/10) * bigSpeed;
    const smSpeed   = -(10/ 6) * medSpeed;
    const tinySpeed = -(16/ 8) * bigSpeed;

    let frameId;
    const clock = new THREE.Clock();
    const animate = () => {
      frameId = requestAnimationFrame(animate);
      const dt = clock.getDelta();
      const t  = clock.elapsedTime;

      bigGear.rotation.z  += bigSpeed  * dt;
      medGear.rotation.z  += medSpeed  * dt;
      smGear.rotation.z   += smSpeed   * dt;
      tinyGear.rotation.z += tinySpeed * dt;

      gearGroup.rotation.x = Math.sin(t * 0.18) * 0.12;
      gearGroup.rotation.y = Math.sin(t * 0.12) * 0.08;
      particles.rotation.y += 0.00015;

      controls.update();
      renderer.render(scene, camera);
    };
    animate();

    const onResize = () => {
      const nw = mount.clientWidth;
      const nh = mount.clientHeight;
      camera.aspect = nw / nh;
      camera.updateProjectionMatrix();
      renderer.setSize(nw, nh);
    };
    window.addEventListener('resize', onResize);

    return () => {
      cancelAnimationFrame(frameId);
      controls.dispose();
      window.removeEventListener('resize', onResize);
      renderer.dispose();
      if (mount.contains(renderer.domElement)) mount.removeChild(renderer.domElement);
    };
  }, []);

  return (
    <section className="home-section">

      {/* ── Left column: text + terminal ── */}
      <div className="hero-content">
        <div className="hero-label">// Computer Engineering · IPB University · Bogor</div>

        <h1 className="hero-title">
          Engineer at<br />
          <span className="hero-title-gradient">Every Layer.</span><br />
          Hardware to Code.
        </h1>

        <p className="hero-sub">
          Mechanical · Electrical · IoT · Embedded · Robotics · Software · 3D Design
        </p>

        <p className="hero-desc">
          Naufal Auzan — final-year Computer Engineering student at IPB University
          yang membangun sistem dari komponen fisik hingga aplikasi digital.
          Dari chassis UGV berbasis AI hingga sistem IoT real-time.
        </p>

        <div className="hero-tags">
          {tags.map(t => <span key={t} className="tag">{t}</span>)}
        </div>

        <div className="hero-cta">
          <button className="btn-primary" onClick={() => onNavigate('projects')}>
            View Projects
          </button>
          <button className="btn-outline" onClick={() => onNavigate('contact')}>
            Get In Touch
          </button>
        </div>

        {/* Terminal — bagian dari kolom kiri, di bawah CTA */}
        <div className="hero-terminal">
          <div className="terminal-bar">
            <div className="tb tb-r" />
            <div className="tb tb-y" />
            <div className="tb tb-g" />
            <span className="terminal-title">engineer.sh</span>
          </div>
          <div className="terminal-body">
            <div><span className="t-prompt">$ </span><span className="t-cmd">whoami</span></div>
            <span className="t-out">polymath_engineer@system:~</span>
            <br />
            <div><span className="t-prompt">$ </span><span className="t-cmd">cat skills.json</span></div>
            <span className="t-out">{'{'}</span>
            <span className="t-out">&nbsp;&nbsp;"mechanical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"electrical": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"IoT": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"robotics": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"embedded": <span className="t-val">true</span>,</span>
            <span className="t-out">&nbsp;&nbsp;"3d_design": <span className="t-val">true</span></span>
            <span className="t-out">{'}'}</span>
            <br />
            <div><span className="t-prompt">$ </span><span className="t-cmd">status</span></div>
            <span className="t-out">→ <span className="t-val">READY TO BUILD</span> <span className="t-cursor" /></span>
          </div>
        </div>
      </div>

      {/* ── Right column: 3D gear, full & unobstructed ── */}
      <div className="hero-3d-wrapper">
        <div className="hero-3d" ref={mountRef} />
        <div className="drag-hint">⟳ drag to rotate · scroll to zoom</div>
      </div>

    </section>
  );
}
